 1	import type { FC } from 'react';
 2	import { Link } from 'react-router-dom-v5-compat';
 3	import { getResourceUrl } from 'src/modules/Providers/utils/helpers/getResourceUrl';
 4	
 5	import { ConsoleTimestamp } from '@components/ConsoleTimestamp/ConsoleTimestamp';
 6	import SectionHeading from '@components/headers/SectionHeading';
 7	import type { IoK8sApiCoreV1Pod } from '@kubev2v/types';
 8	import { ResourceLink } from '@openshift-console/dynamic-plugin-sdk';
 9	import { Stack } from '@patternfly/react-core';
10	import { Table, Tbody, Td, Th, Thead, Tr } from '@patternfly/react-table';
11	import { PodModelGroupVersionKind } from '@utils/crds/common/models';
12	import { getName, getNamespace, getUID } from '@utils/crds/common/selectors';
13	import { isEmpty } from '@utils/helpers';
14	import { useForkliftTranslation } from '@utils/i18n';
15	
16	type MigrationPodsTableProps = {
17	  pods: IoK8sApiCoreV1Pod[];
18	};
19	
20	const getPodLogsLink = (pod: IoK8sApiCoreV1Pod) =>
21	  getResourceUrl({
22	    name: getName(pod),
23	    namespace: getNamespace(pod),
24	    reference: 'pods',
25	  });
26	
27	const MigrationPodsTable: FC<MigrationPodsTableProps> = ({ pods }) => {
28	  const { t } = useForkliftTranslation();
29	
30	  if (isEmpty(pods)) {
31	    return null;
32	  }
33	
34	  return (
35	    <>
36	      <SectionHeading
37	        text={t('Pods')}
38	        textComponent="h3"
39	        className="migration-status-expanded-page__resource-list-header"
40	      />
41	      <Table>
42	        <Thead>
43	          <Tr>
44	            <Th width={40}>{t('Name')}</Th>
45	            <Th width={20}>{t('Description')}</Th>
46	            <Th>{t('Completed at')}</Th>
47	          </Tr>
48	        </Thead>
49	        <Tbody>
50	          {pods.map((pod) => (
51	            <Tr key={getUID(pod)}>
52	              <Td width={40}>
53	                <ResourceLink
54	                  groupVersionKind={PodModelGroupVersionKind}
55	                  name={getName(pod)}
56	                  namespace={getNamespace(pod)}
57	                />
58	              </Td>
59	              <Td width={20}>
60	                <Stack>
61	                  <>{pod?.status?.phase}</>
62	                  <Link to={`${getPodLogsLink(pod)}/logs`}>{t('View logs')}</Link>
63	                </Stack>
64	              </Td>
65	              <Td>
66	                <ConsoleTimestamp
67	                  timestamp={pod?.metadata?.creationTimestamp ?? null}
68	                  showGlobalIcon={false}
69	                />
70	              </Td>
71	            </Tr>
72	          ))}
73	        </Tbody>
74	      </Table>
75	    </>
76	  );
77	};
78	
79	export default MigrationPodsTable;

